# Bash completion for padctl. Generated by scripts/generate-shell-completions.py.

_padctl_complete_files()
{
    local append=${1:-false} candidate
    [[ $append == true ]] || COMPREPLY=()
    while IFS= read -r candidate; do
        COMPREPLY+=("$candidate")
    done < <(compgen -f -- "$cur")
    compopt -o filenames 2>/dev/null || true
}

_padctl_complete_dirs()
{
    local candidate
    COMPREPLY=()
    while IFS= read -r candidate; do
        COMPREPLY+=("$candidate")
    done < <(compgen -d -- "$cur")
    compopt -o filenames 2>/dev/null || true
}

_padctl_complete_words()
{
    COMPREPLY=( $(compgen -W "$1" -- "$cur") )
}

_padctl_add_mapping_reply()
{
    local candidate=$1 existing
    [[ $candidate == "$cur"* ]] || return 0
    for existing in "${COMPREPLY[@]}"; do
        [[ $existing == "$candidate" ]] && return 0
    done
    COMPREPLY+=("$candidate")
}

_padctl_complete_mappings()
{
    local candidate mapping_file
    COMPREPLY=()
    while IFS= read -r candidate; do
        [[ -n $candidate ]] && _padctl_add_mapping_reply "$candidate"
    done < <(command padctl list-mappings --names 2>/dev/null || true)
    for mapping_file in mappings/*.toml; do
        [[ -f $mapping_file ]] || continue
        candidate=${mapping_file##*/}
        _padctl_add_mapping_reply "${candidate%.toml}"
    done
}

_padctl_apply_prefix()
{
    local prefix=$1 i
    [[ -n $prefix ]] || return 0
    for ((i = 0; i < ${#COMPREPLY[@]}; i++)); do
        COMPREPLY[i]="${prefix}${COMPREPLY[i]}"
    done
}

_padctl_complete_value()
{
    local kind=$1 prefix=${2:-} mapping_replies candidate
    case "$kind" in
        file)
            _padctl_complete_files
            ;;
        dir)
            _padctl_complete_dirs
            ;;
        scope)
            _padctl_complete_words "system user package"
            ;;
        mapping)
            _padctl_complete_mappings
            ;;
        mapping_or_file)
            _padctl_complete_mappings
            mapping_replies=$(printf '%s\n' "${COMPREPLY[@]}")
            _padctl_complete_files
            while IFS= read -r candidate; do
                [[ -n $candidate ]] && _padctl_add_mapping_reply "$candidate"
            done <<< "$mapping_replies"
            ;;
        *)
            COMPREPLY=()
            ;;
    esac
    _padctl_apply_prefix "$prefix"
}

_padctl_context_options()
{
    case "$1" in
        global) printf '%s\n' "--config --config-dir --mapping --validate --pid-file --doc-gen --output -h --help -V --version" ;;
        install) printf '%s\n' "--prefix --destdir --immutable --no-immutable --mapping --force-mapping --force-binding --user-service --no-user-service --no-enable --no-start --scope --help -h" ;;
        uninstall) printf '%s\n' "--prefix --destdir --immutable --no-immutable --mapping --scope --help -h" ;;
        scan) printf '%s\n' "--config-dir --help -h" ;;
        list-mappings) printf '%s\n' "--config-dir --names --help -h" ;;
        reload) printf '%s\n' "--pid --help -h" ;;
        switch) printf '%s\n' "--persist --device --socket --help -h" ;;
        output-profile) printf '%s\n' "--help -h" ;;
        output-profile/list) printf '%s\n' "--device --help -h" ;;
        output-profile/select) printf '%s\n' "--device --help -h" ;;
        output-profile/reset) printf '%s\n' "--device --help -h" ;;
        status) printf '%s\n' "--socket --help -h" ;;
        devices) printf '%s\n' "--socket --help -h" ;;
        doctor) printf '%s\n' "--socket --help -h" ;;
        dump) printf '%s\n' "--help -h" ;;
        dump/enable) printf '%s\n' "--socket --help -h" ;;
        dump/disable) printf '%s\n' "--socket --help -h" ;;
        dump/status) printf '%s\n' "--socket --help -h" ;;
        dump/export) printf '%s\n' "--period --socket -o --help -h" ;;
