    esac
}

_padctl_context_subcommands()
{
    case "$1" in
        output-profile) printf '%s\n' "list select reset" ;;
        dump) printf '%s\n' "enable disable status export clear" ;;
        config) printf '%s\n' "list init edit test" ;;
    esac
}

_padctl_context_position_kind()
{
    case "$1" in
        switch) printf '%s\n' "mapping" ;;
        output-profile/select) printf '%s\n' "plain" ;;
        config/edit) printf '%s\n' "mapping" ;;
        config/test) printf '%s\n' "mapping_or_file" ;;
    esac
}

