        uninstall:--destdir) printf '%s\n' "dir" ;;
        uninstall:--mapping) printf '%s\n' "mapping" ;;
        uninstall:--scope) printf '%s\n' "scope" ;;
        scan:--config-dir) printf '%s\n' "dir" ;;
